import{_ as i,o as l,c as t,a3 as e}from"./chunks/framework.DACwFHq9.js";const c=JSON.parse('{"title":"AHK Automator 游戏助手与路线包概念想法记录","description":"","frontmatter":{},"headers":[],"relativePath":"design/ahk-automator-game-assistant-concepts.md","filePath":"design/ahk-automator-game-assistant-concepts.md","lastUpdated":1782220850000}'),o={name:"design/ahk-automator-game-assistant-concepts.md"};function r(h,a,n,s,u,p){return l(),t("div",null,[...a[0]||(a[0]=[e('<h1 id="ahk-automator-游戏助手与路线包概念想法记录" tabindex="-1">AHK Automator 游戏助手与路线包概念想法记录 <a class="header-anchor" href="#ahk-automator-游戏助手与路线包概念想法记录" aria-label="Permalink to &quot;AHK Automator 游戏助手与路线包概念想法记录&quot;">​</a></h1><blockquote><p>状态：Concept / 想法记录 说明：本文只保留讨论过程中出现的产品与交互方向，不是待施工计划，不包含实现步骤、接口承诺、验收标准或排期。相关前置能力未完成前，本文不能作为开发任务拆解依据。</p></blockquote><h2 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to &quot;背景&quot;">​</a></h2><p>AHK Automator 已经具备窗口截图、区域截图、点击、按键、录制、项目导入导出等基础自动化能力。在此基础上，曾经讨论过一个更偏“助手”的方向：让用户或 AI 可以围绕某个游戏、软件或重复工作场景，沉淀一组可复用的点位、识别规则、路线和任务习惯。</p><p>这个想法的核心不是立刻扩展插件能力，而是记录一种可能的产品形态：AIO Hub 可以把底层自动化能力包装成更易分享、更易由 AI 协作维护的场景包。</p><h2 id="核心想法" tabindex="-1">核心想法 <a class="header-anchor" href="#核心想法" aria-label="Permalink to &quot;核心想法&quot;">​</a></h2><h3 id="低频识别-高频执行" tabindex="-1">低频识别，高频执行 <a class="header-anchor" href="#低频识别-高频执行" aria-label="Permalink to &quot;低频识别，高频执行&quot;">​</a></h3><p>一些格子移动类游戏或固定界面软件并不需要每一步都重新理解屏幕。更自然的方式可能是：</p><ul><li>低频识别：用 OCR、像素、模板或人工确认来读取任务文本、地图名、按钮状态、异常弹窗。</li><li>高频执行：用固定点位、方向格点、快捷键、路线队列来完成连续移动和重复操作。</li></ul><p>这种分工可以减少识别延迟，也让 AI 更容易解释和维护自动化过程。</p><h3 id="场景包-而不是把具体游戏写进插件" tabindex="-1">场景包，而不是把具体游戏写进插件 <a class="header-anchor" href="#场景包-而不是把具体游戏写进插件" aria-label="Permalink to &quot;场景包，而不是把具体游戏写进插件&quot;">​</a></h3><p>如果未来出现“游戏助手”或“路线助手”类能力，它更适合把通用能力和具体内容分开：</p><ul><li>通用层关注录制、点位、路线、检测、日志、失败暂停、用户接管等基础体验。</li><li>场景层保存某个游戏或软件自己的窗口特征、地图称呼、路线文本、按钮点位、任务习惯。</li></ul><p>具体游戏中的 NPC、地图、每日任务、wiki 路线等内容，应更像可导入导出的场景包，而不是写死在 AHK Automator 插件核心里。</p><h3 id="附属插件优先于主插件叠功能" tabindex="-1">附属插件优先于主插件叠功能 <a class="header-anchor" href="#附属插件优先于主插件叠功能" aria-label="Permalink to &quot;附属插件优先于主插件叠功能&quot;">​</a></h3><p>更进一步地看，具体游戏助手不一定应该作为 AHK Automator 主插件里的“高级模式”出现。现在的开发环境已经变成了：围绕一个明确游戏或场景，让 AI 辅助生成、调整、安装一个附属插件，往往比在原插件里叠出一层通用抽象编辑器、再解决它如何和内置 AI 协作要便宜得多。</p><p>因此这个方向不应沿用传统“大插件不断加配置层”的思路。更合理的边界可能是：</p><ul><li>AHK Automator 保持为稳定底座：窗口、截图、点位、输入、运行日志、失败暂停、用户接管等基础能力。</li><li>具体游戏、具体软件或具体工作流，由附属插件承载自己的界面、术语、路线格式、检测逻辑和 AI 协作提示。</li><li>当多个附属插件反复需要同一种能力时，再把能力下沉到 AHK Automator 或宿主平台，而不是预先在主插件里设计庞大的抽象系统。</li></ul><p>这样既能保留快速定制的空间，也避免为了覆盖所有场景而把主插件做成复杂的半成品编辑器。</p><h3 id="ai-适合参与-整理-和-解释" tabindex="-1">AI 适合参与“整理”和“解释” <a class="header-anchor" href="#ai-适合参与-整理-和-解释" aria-label="Permalink to &quot;AI 适合参与“整理”和“解释”&quot;">​</a></h3><p>AI 在这个方向里更适合承担辅助角色，例如：</p><ul><li>把用户录制的点击整理成更清晰的路线描述。</li><li>从 wiki、攻略或用户笔记中提取地点序列。</li><li>帮用户解释某条路线为什么会失败。</li><li>根据截图、OCR 结果和日志推测当前卡住的位置。</li><li>把一组重复操作整理成更易读、可复用的场景资料。</li></ul><p>这类协作不要求一开始就把全部流程变成复杂的规则系统。它可以先作为“帮用户整理自动化经验”的概念存在。</p><h3 id="用户体验上的感觉" tabindex="-1">用户体验上的感觉 <a class="header-anchor" href="#用户体验上的感觉" aria-label="Permalink to &quot;用户体验上的感觉&quot;">​</a></h3><p>理想状态下，这类能力不应该像编写底层脚本那样冷冰冰，也不应该把用户推进过度复杂的配置表单。它更像一个工作台：</p><ul><li>用户能看到当前目标窗口和关键截图。</li><li>用户能保存命名点位、方向格点、识别区域和备注。</li><li>用户能把一次成功操作沉淀成可复用路线。</li><li>用户能在失败时暂停、接管、修正，再继续整理。</li><li>AI 可以阅读这些资料，并提出下一步整理建议。</li></ul><p>重点是让经验逐渐变得可复用，而不是一上来就要求完整自动化。</p><h2 id="可能的应用场景" tabindex="-1">可能的应用场景 <a class="header-anchor" href="#可能的应用场景" aria-label="Permalink to &quot;可能的应用场景&quot;">​</a></h2><ul><li>格子移动类游戏的日常路线整理。</li><li>固定 UI 软件中的重复操作。</li><li>半自动素材整理、窗口切换、批量点击、状态确认。</li><li>需要用户偶尔接管的辅助操作流。</li><li>把社区攻略或个人笔记整理成更结构化的操作资料。</li></ul><p>这些场景只是想象空间，不代表会在某个版本中实现。</p><h2 id="暂不展开的内容" tabindex="-1">暂不展开的内容 <a class="header-anchor" href="#暂不展开的内容" aria-label="Permalink to &quot;暂不展开的内容&quot;">​</a></h2><p>以下内容曾在讨论中出现过，但目前不应写成计划：</p><ul><li>独立游戏助手或附属场景插件的具体实现。</li><li>插件依赖解析、能力注册表或插件拓扑排序。</li><li>Profile / Recipe / Detector / Navigation Driver 的具体 schema。</li><li>任务调度器、暂停恢复状态机、运行 API。</li><li>Wiki 路线导入器、路线录制器、场景包导入导出。</li><li>OpenCV、VLM 或其他视觉能力接入方式。</li></ul><p>这些都依赖更完整的宿主能力、插件系统设计和产品验证。当前只保留“方向感”，不保留“施工表”。</p><h2 id="记录结论" tabindex="-1">记录结论 <a class="header-anchor" href="#记录结论" aria-label="Permalink to &quot;记录结论&quot;">​</a></h2><p>这个方向值得作为 AHK Automator 的远期产品想象保留：把自动化从一次性脚本，逐步提升为可记录、可解释、可分享、可由 AI 协作整理的场景经验库。</p><p>但在前置能力没有明确完成前，不应把它拆成插件 Plan，也不应让它进入待施工队列。</p>',37)])])}const m=i(o,[["render",r]]);export{c as __pageData,m as default};
